      {"type":"quiz","question":"Как попросить счёт в ресторане?","options":[{"id":"a","text":"L'addition, s'il vous plaît","correct":True},{"id":"b","text":"Le prix, s'il vous plaît","correct":False},{"id":"c","text":"Combien?","correct":False},{"id":"d","text":"La carte, s'il vous plaît","correct":False}]},
